/**
 * Safe template (committed). Copy to `hourly-fetch-with-marketing.js` (gitignored), fill YOUR_*.
 * Merge into workflow JSON: `node n8n/snippets/merge-hourly-fetch.mjs` (prefers local gitignored file).
 */
const apikey = "YOUR_ROLI_ANON_KEY";
let base = "YOUR_ROLI_SUPABASE_URL";
base = base.replace(/\/+$/, "");

const mktApikey = "YOUR_MARKETING_AAR_ANON_KEY";
let mktBase = "YOUR_MARKETING_AAR_REST_URL";
mktBase = mktBase.replace(/\/+$/, "");

/** PostgREST base: `https://<ref>.supabase.co/rest/v1` */
function toRestV1(origin) {
  const u = origin.replace(/\/+$/, "");
  return /\/rest\/v1$/i.test(u) ? u : `${u}/rest/v1`;
}
base = toRestV1(base);
mktBase = toRestV1(mktBase);

const hdr = { apikey, Authorization: `Bearer ${apikey}` };
const hdrMkt = { apikey: mktApikey, Authorization: `Bearer ${mktApikey}` };

const now = new Date();
const centralStr = now.toLocaleDateString("en-CA", {
  timeZone: "America/Chicago",
});
const centralHour = Number(
  now.toLocaleString("en-US", {
    timeZone: "America/Chicago",
    hour: "numeric",
    hour12: false,
  })
);

const centralNow = new Date(
  now.toLocaleString("en-US", { timeZone: "America/Chicago" })
);
const dayOfWeek = centralNow.getDay();
const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(centralNow);
monday.setDate(monday.getDate() - mondayOffset);
const mondayStr = monday.toISOString().slice(0, 10);
const daysThisWeek = Math.min(dayOfWeek === 0 ? 5 : dayOfWeek, 5);

function isPlaceholder(v) {
  return !v || String(v).startsWith("YOUR_");
}

const mktConfigured = !isPlaceholder(mktApikey) && !isPlaceholder(mktBase);

const mktCols =
  "report_date,total_cost,cpc,total_calls,total_sales,total_premium,avg_premium,roas,marketing_acq_pct";

/** Isolated GET so a Marketing 401/RLS error does not fail the whole ROLI fetch. */
const mktGet = async (queryAfterSelect) => {
  if (!mktConfigured) return [];
  try {
    const data = await this.helpers.httpRequest({
      method: "GET",
      url: `${mktBase}/company_daily_metrics?select=${mktCols}&${queryAfterSelect}`,
      headers: hdrMkt,
      json: true,
    });
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
};

const DEFAULT_LEAD_COST = 60;
const DEFAULT_AVG_PREM = 1150;

function rowFromMkt(r) {
  const cpc = Number(r.cpc) || DEFAULT_LEAD_COST;
  const avgPrem = Number(r.avg_premium) || DEFAULT_AVG_PREM;
  const tCost = Number(r.total_cost) || 0;
  const tSales = Number(r.total_sales) || 0;
  const costPerSale = tSales > 0 ? Math.round(tCost / tSales) : 0;
  return {
    report_date: String(r.report_date ?? "").slice(0, 10),
    total_cost: tCost,
    cpc,
    total_calls: Number(r.total_calls) || 0,
    total_sales: tSales,
    total_premium: Number(r.total_premium) || 0,
    avg_premium: avgPrem,
    roas: Number(r.roas) || 0,
    marketing_acq_pct: Number(r.marketing_acq_pct) || 0,
    cost_per_sale: costPerSale,
  };
}

/** Mean of up to 7 completed AAR days (report_date < centralStr) for intraday CPC / org premium. */
function averageMarketingRows(rows, anchorDate) {
  if (!rows || rows.length === 0) return null;
  const norm = rows.map(r => rowFromMkt(r));
  const dates = [
    ...new Set(norm.map(r => String(r.report_date).slice(0, 10))),
  ].sort();
  const from = dates[0] || anchorDate;
  const to = dates[dates.length - 1] || anchorDate;
  const n = norm.length;
  const mean = pick => norm.reduce((s, r) => s + pick(r), 0) / n;
  const sumCost = norm.reduce((s, r) => s + r.total_cost, 0);
  const sumSales = norm.reduce((s, r) => s + r.total_sales, 0);
  const costPerSale = sumSales > 0 ? Math.round(sumCost / sumSales) : 0;
  return {
    report_date: anchorDate,
    total_cost: mean(r => r.total_cost),
    cpc: mean(r => r.cpc),
    total_calls: Math.round(mean(r => r.total_calls)),
    total_sales: Math.round(mean(r => r.total_sales)),
    total_premium: mean(r => r.total_premium),
    avg_premium: mean(r => r.avg_premium),
    roas: mean(r => r.roas),
    marketing_acq_pct: mean(r => r.marketing_acq_pct),
    cost_per_sale: costPerSale,
    summary_mode: "rolling_7d_intraday",
    rolling_window: { from, to, days: n },
  };
}

const [
  roster,
  weeklyData,
  intradayData,
  pipelineData,
  poolData,
  weeklyPoolData,
  mktExact,
  mktLast7,
] = await Promise.all([
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/agents?select=name,site,tier,manager&is_active=eq.true`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/daily_scrape_data?select=agent_name,scrape_date,ib_leads_delivered,ob_leads_delivered,ib_sales,ob_sales,custom_sales&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}&order=scrape_date.asc`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/intraday_snapshots?select=agent_name,scrape_hour,total_dials,talk_time_minutes,ib_leads_delivered,ib_sales,ob_leads_delivered,ob_sales,ib_premium,ob_premium,custom_premium,pool_dials,pool_talk_minutes,pool_self_assigned,pool_answered,pool_long_calls&scrape_date=eq.${centralStr}&order=scrape_hour.desc`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/pipeline_compliance_daily?select=agent_name,past_due_follow_ups,new_leads,call_queue_count,todays_follow_ups&scrape_date=eq.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/leads_pool_daily_data?select=agent_name,calls_made,talk_time_minutes,self_assigned_leads,answered_calls,long_calls,sales_made&scrape_date=eq.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/leads_pool_daily_data?select=agent_name,sales_made&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  mktGet(`report_date=eq.${centralStr}&limit=1`),
  mktGet(`report_date=lt.${centralStr}&order=report_date.desc&limit=7`),
]);

const mktTodayEq = Array.isArray(mktExact) && mktExact[0] ? mktExact[0] : null;
let mktRow = mktTodayEq;
if (!mktRow && mktConfigured) {
  const mktLatest = await mktGet("order=report_date.desc&limit=1");
  mktRow = mktLatest[0] || null;
}

const last7 = Array.isArray(mktLast7) ? mktLast7 : [];
const blended = averageMarketingRows(last7, centralStr);

let marketingDaily = null;
let leadCostOverride = DEFAULT_LEAD_COST;
let avgPremiumOverride = DEFAULT_AVG_PREM;

if (blended) {
  marketingDaily = blended;
  leadCostOverride = Math.round(blended.cpc);
  avgPremiumOverride = Math.round(blended.avg_premium);
} else if (mktRow) {
  marketingDaily = rowFromMkt(mktRow);
  leadCostOverride = Math.round(marketingDaily.cpc);
  avgPremiumOverride = Math.round(marketingDaily.avg_premium);
}

if (mktTodayEq) {
  const todayBody = rowFromMkt(mktTodayEq);
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: `${base}/daily_marketing_summary?on_conflict=report_date`,
      headers: {
        ...hdr,
        "Content-Type": "application/json",
        Prefer: "resolution=merge-duplicates",
      },
      body: todayBody,
      json: true,
    });
  } catch (syncErr) {
    // Table may not exist yet or RLS — workflow continues
  }
}

if (!roster || roster.length === 0) {
  throw new Error("No active agents found");
}

const rosterMap = {};
for (const a of roster) rosterMap[a.name] = a;

const weeklyByAgent = {};
for (const r of weeklyData || []) {
  if (!rosterMap[r.agent_name]) continue;
  if (!weeklyByAgent[r.agent_name]) weeklyByAgent[r.agent_name] = [];
  weeklyByAgent[r.agent_name].push({
    date: r.scrape_date,
    ibLeads: r.ib_leads_delivered || 0,
    obLeads: r.ob_leads_delivered || 0,
    ibSales: r.ib_sales || 0,
    obSales: r.ob_sales || 0,
    customSales: r.custom_sales || 0,
  });
}

const weeklyPoolSales = {};
for (const r of weeklyPoolData || []) {
  if (!rosterMap[r.agent_name]) continue;
  weeklyPoolSales[r.agent_name] =
    (weeklyPoolSales[r.agent_name] || 0) + (r.sales_made || 0);
}

const intradayMap = {};
for (const r of intradayData || []) {
  if (!intradayMap[r.agent_name] && rosterMap[r.agent_name]) {
    intradayMap[r.agent_name] = r;
  }
}

const pipeMap = {};
for (const r of pipelineData || []) {
  if (rosterMap[r.agent_name]) pipeMap[r.agent_name] = r;
}

const poolMapData = {};
for (const r of poolData || []) {
  if (rosterMap[r.agent_name]) poolMapData[r.agent_name] = r;
}

return [
  {
    json: {
      scrapeDate: centralStr,
      centralHour,
      mondayStr,
      daysThisWeek,
      rosterMap,
      weeklyByAgent,
      weeklyPoolSales,
      intradayMap,
      pipeMap,
      poolMapData,
      agentCount: roster.length,
      marketingDaily,
      leadCostOverride,
      avgPremiumOverride,
    },
  },
];

const {
  scrapeDate,
  centralHour,
  daysThisWeek,
  rosterMap,
  weeklyByAgent,
  weeklyPoolSales,
  intradayMap,
  pipeMap,
  poolMapData,
  agentCount,
  leadCostOverride,
  avgPremiumOverride,
} = $input.first().json;

const DEFAULT_LC = 60;
const lc =
  typeof leadCostOverride === 'number' && leadCostOverride > 0 ? leadCostOverride : DEFAULT_LC;

const CFG = {
  DAILY_LEADS: 7,
  LEAD_COST: lc,
  CR_TARGET: 15,
  CR_FLOOR: 10,
  CR_CRISIS: 7,
  CR_CRISIS_DAYS: 3,
  MAX_PIPELINE: 30,
  PIPELINE_CRITICAL: 40,
  POOL_DAILY_ASSIGNS: 5,
  POOL_WEEKLY_SALES: 1,
  POOL_MIN_ASSIGN_RATE: 30,
  AVG_PREMIUM_ORG: typeof avgPremiumOverride === 'number' && avgPremiumOverride > 0 ? avgPremiumOverride : 1150,
};

function computeWeeklyCR(rows) {
  if (!rows || rows.length === 0) return { weeklyCR: null, dailyCRs: [], weekLeads: 0, weekSales: 0 };
  const dailyCRs = rows.map((r) => {
    const leads = r.ibLeads + r.obLeads;
    const sales = r.ibSales + r.obSales + r.customSales;
    return leads > 0 ? (sales / leads) * 100 : 0;
  });
  const totalLeads = rows.reduce((s, r) => s + r.ibLeads + r.obLeads, 0);
  const totalSales = rows.reduce((s, r) => s + r.ibSales + r.obSales + r.customSales, 0);
  return {
    weeklyCR: totalLeads > 0 ? (totalSales / totalLeads) * 100 : null,
    dailyCRs,
    weekLeads: totalLeads,
    weekSales: totalSales,
  };
}

function consLow(dailyCRs, threshold) {
  let c = 0;
  for (let i = dailyCRs.length - 1; i >= 0; i--) {
    if (dailyCRs[i] < threshold) c++;
    else break;
  }
  return c;
}

function recommend(weeklyCR, dailyCRs, weekLeads, weekSales, pipe, intra, pool, poolWeekSales) {
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const pipeSize = (pipe?.new_leads ?? 0) + (pipe?.todays_follow_ups ?? 0) + pastDue;
  const poolAssigns = pool?.self_assigned_leads ?? 0;
  const poolAnswered = pool?.answered_calls ?? 0;
  const assignRate = poolAnswered > 0 ? (poolAssigns / poolAnswered) * 100 : 0;
  const consLowDays = consLow(dailyCRs, CFG.CR_CRISIS);
  const isMidDay = centralHour >= 12;

  if (pastDue > 3)
    return {
      action: 'WORK_FOLLOWUPS',
      severity: 'critical',
      reason: `${pastDue} past due follow-ups — $${pastDue * CFG.LEAD_COST} in lead spend at risk.`,
    };

  if (pipeSize > CFG.PIPELINE_CRITICAL)
    return {
      action: 'CLEAR_PIPELINE',
      severity: 'critical',
      reason: `Pipeline at ${pipeSize} leads (critical threshold: ${CFG.PIPELINE_CRITICAL}). Revenue rotting.`,
    };

  if (consLowDays >= CFG.CR_CRISIS_DAYS && weeklyCR !== null)
    return {
      action: 'REVIEW_QUALITY',
      severity: 'critical',
      reason: `CR below ${CFG.CR_CRISIS}% for ${consLowDays} consecutive days (weekly: ${weeklyCR.toFixed(0)}%). Audit calls.`,
    };

  if (pastDue > 0)
    return {
      action: 'WORK_FOLLOWUPS',
      severity: 'warning',
      reason: `${pastDue} past due follow-up${pastDue > 1 ? 's' : ''}. Work before pool or inbound.`,
    };

  if (pipeSize > CFG.MAX_PIPELINE)
    return {
      action: 'CLEAR_PIPELINE',
      severity: 'warning',
      reason: `Pipeline at ${pipeSize} leads (max: ${CFG.MAX_PIPELINE}). Close out or withdraw stale leads.`,
    };

  if (weeklyCR !== null && weeklyCR < CFG.CR_FLOOR)
    return {
      action: 'FOCUS_PIPELINE',
      severity: 'warning',
      reason: `Weekly CR at ${weeklyCR.toFixed(0)}% (target: ${CFG.CR_TARGET}%). Focus on converting existing leads.`,
    };

  if (isMidDay && poolAssigns < 3)
    return {
      action: 'GET_IN_POOL',
      severity: 'warning',
      reason: `Only ${poolAssigns} pool self-assigns today (target: ${CFG.POOL_DAILY_ASSIGNS}). Find 5 people to follow up with.`,
    };

  if (poolAnswered >= 10 && assignRate < CFG.POOL_MIN_ASSIGN_RATE)
    return {
      action: 'GET_IN_POOL',
      severity: 'warning',
      reason: `Pool assign rate at ${assignRate.toFixed(0)}% (min: ${CFG.POOL_MIN_ASSIGN_RATE}%). Self-assign every answered contact.`,
    };

  if (weeklyCR !== null && weeklyCR >= CFG.CR_TARGET && pipeSize <= 20 && pastDue === 0)
    return {
      action: 'TAKE_MORE_LEADS',
      severity: 'info',
      reason: `CR at ${weeklyCR.toFixed(0)}% with clean pipeline (${pipeSize}). Eligible for additional inbound leads.`,
    };

  if (weeklyCR !== null && weeklyCR >= CFG.CR_FLOOR && pipeSize >= 10 && pipeSize <= CFG.MAX_PIPELINE)
    return {
      action: 'STAY_IN_QUEUE',
      severity: 'info',
      reason: `CR at ${weeklyCR.toFixed(0)}% · Pipeline ${pipeSize} — keep working inbound queue. ${
        CFG.CR_TARGET - weeklyCR > 0 ? (CFG.CR_TARGET - weeklyCR).toFixed(0) + '% to bonus-lead eligibility.' : ''
      }`,
    };

  if (poolAssigns < CFG.POOL_DAILY_ASSIGNS && poolWeekSales < CFG.POOL_WEEKLY_SALES && pipeSize < 10)
    return {
      action: 'GET_IN_POOL',
      severity: 'info',
      reason: `Light pipeline (${pipeSize}) and ${poolAssigns}/${CFG.POOL_DAILY_ASSIGNS} pool assigns. Build tomorrow's follow-up pipeline from pool.`,
    };

  const parts = [];
  if (weeklyCR !== null) parts.push(`CR ${weeklyCR.toFixed(0)}%`);
  parts.push(`Pipeline ${pipeSize}`);
  if (poolAssigns > 0) parts.push(`Pool ${poolAssigns} assigns`);
  if (poolWeekSales > 0) parts.push(`Pool ${poolWeekSales} sales this week`);
  return { action: 'ON_TRACK', severity: 'info', reason: parts.join(' · ') + ' — on track.' };
}

const results = [];
for (const [name, agent] of Object.entries(rosterMap)) {
  const weekRows = weeklyByAgent[name] || [];
  const { weeklyCR, dailyCRs, weekLeads, weekSales } = computeWeeklyCR(weekRows);
  const pipe = pipeMap[name];
  const pool = poolMapData[name];
  const intra = intradayMap[name];
  const poolWeekSales = weeklyPoolSales[name] || 0;

  const poolSelfAssigned = pool?.self_assigned_leads ?? 0;
  const poolAnswered = pool?.answered_calls ?? 0;
  const poolDials = pool?.calls_made ?? 0;
  const poolLongCalls = pool?.long_calls ?? 0;
  const totalDials = intra?.total_dials ?? 0;
  const todaysLeads = (intra?.ib_leads_delivered ?? 0) + (intra?.ob_leads_delivered ?? 0);
  const todaysSales = (intra?.ib_sales ?? 0) + (intra?.ob_sales ?? 0);
  const todaysCR = todaysLeads > 0 ? (todaysSales / todaysLeads) * 100 : null;
  const todaysPremium = (intra?.ib_premium ?? 0) + (intra?.ob_premium ?? 0) + (intra?.custom_premium ?? 0);
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const pipeSize = pipe ? (pipe.new_leads ?? 0) + (pipe.todays_follow_ups ?? 0) + pastDue : null;

  const rec = recommend(weeklyCR, dailyCRs, weekLeads, weekSales, pipe, intra, pool, poolWeekSales);

  results.push({
    name,
    site: agent.site,
    manager: agent.manager || null,
    ...rec,
    weeklyCR: weeklyCR !== null ? Math.round(weeklyCR * 10) / 10 : null,
    weekLeads,
    weekSales,
    todaysCR: todaysCR !== null ? Math.round(todaysCR * 10) / 10 : null,
    todaysLeads,
    todaysSales,
    todaysPremium: Math.round(todaysPremium),
    todaysDials: totalDials,
    todaysTalkMin: Math.round(intra?.talk_time_minutes ?? 0),
    pastDue,
    pipelineSize: pipeSize,
    poolDials,
    poolSelfAssigned,
    poolAnswered,
    poolLongCalls,
    poolWeekSales,
    poolOnTrack: poolWeekSales >= CFG.POOL_WEEKLY_SALES,
  });
}

const sev = { critical: 0, warning: 1, info: 2 };
results.sort((a, b) => sev[a.severity] - sev[b.severity]);

const critical = results.filter((r) => r.severity === 'critical');
const warning = results.filter((r) => r.severity === 'warning');
const onTrack = results.filter((r) => r.severity === 'info');

return [
  {
    json: {
      scrapeDate,
      centralHour,
      agentCount,
      daysThisWeek,
      critical,
      warning,
      onTrack,
      results,
      cfg: CFG,
    },
  },
];

const { scrapeDate, centralHour, critical, warning, onTrack, agentCount, daysThisWeek, cfg } = $input.first().json;

const [y, mo, d] = scrapeDate.split('-');
const dt = new Date(+y, +mo - 1, +d);
const dn = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dt.getDay()];
const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][dt.getMonth()];
const dd = `${dn} ${mn} ${+d}, ${y}`;
const ampm = centralHour > 12 ? `${centralHour - 12}:05 PM` : centralHour === 12 ? '12:05 PM' : `${centralHour}:05 AM`;

const ACTION_LABELS = {
  TAKE_MORE_LEADS: ':chart_with_upwards_trend: TAKE MORE LEADS',
  WORK_FOLLOWUPS: ':alarm_clock: WORK FOLLOW-UPS',
  GET_IN_POOL: ':swimmer: GET IN POOL',
  CLEAR_PIPELINE: ':broom: CLEAR PIPELINE',
  REVIEW_QUALITY: ':mag: REVIEW QUALITY',
  FOCUS_PIPELINE: ':dart: FOCUS PIPELINE',
  STAY_IN_QUEUE: ':telephone_receiver: STAY IN QUEUE',
  ON_TRACK: ':white_check_mark: ON TRACK',
};

const fmt = (n) => '$' + Math.round(n).toLocaleString();

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: `Hourly Action Alert \u2014 ${dd}` } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
  `*${ampm} CT*  \u00b7  ${agentCount} agents tracked  \u00b7  Day ${daysThisWeek} of week\n` +
  `*${critical.length}* :rotating_light: critical  \u00b7  *${warning.length}* :warning: warning  \u00b7  *${onTrack.length}* :white_check_mark: on track`
}});

blocks.push({ type: 'divider' });

function formatAgent(a) {
  const siteTag = a.site === 'RMT' ? 'RMT' : 'CLT';
  const crStr = a.weeklyCR !== null ? `Wk CR: ${a.weeklyCR}% (${a.weekSales}/${a.weekLeads})` : 'No CR data';
  const todayCR = a.todaysCR !== null ? `Today: ${a.todaysCR}%` : '';
  const leads = `Leads: ${a.todaysLeads}`;
  const sales = a.todaysSales > 0 ? `Sales: ${a.todaysSales}` : '';
  const prem = a.todaysPremium > 0 ? fmt(a.todaysPremium) : '';
  const pd = a.pastDue > 0 ? `Past Due: ${a.pastDue}` : '';
  const pipe = a.pipelineSize !== null ? `Pipeline: ${a.pipelineSize}` : '';
  const poolStr = a.poolDials > 0 ? `Pool: ${a.poolDials} dials / ${a.poolSelfAssigned} assigns` : '';
  const poolWk = `Pool sales: ${a.poolWeekSales}/${cfg.POOL_WEEKLY_SALES}/wk` + (a.poolOnTrack ? ' :white_check_mark:' : '');

  const statsLine = [leads, sales, prem, crStr, todayCR].filter(Boolean).join(' \u00b7 ');
  const pipePool = [pd, pipe, poolStr, poolWk].filter(Boolean).join(' \u00b7 ');

  return `${ACTION_LABELS[a.action] || a.action} \u2014 *${a.name}*  _(${siteTag})_\n${statsLine}\n${pipePool}\n_\u21b3 ${a.reason}_`;
}

if (critical.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:rotating_light: CRITICAL (${critical.length})*` } });
  for (const a of critical.slice(0, 15)) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: formatAgent(a) } });
  }
  if (critical.length > 15) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_\u2026and ${critical.length - 15} more critical._` }] });
  }
  blocks.push({ type: 'divider' });
}

if (warning.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:warning: WARNING (${warning.length})*` } });
  for (const a of warning.slice(0, 15)) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: formatAgent(a) } });
  }
  if (warning.length > 15) {
    blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `_\u2026and ${warning.length - 15} more warnings._` }] });
  }
  blocks.push({ type: 'divider' });
}

const rmtTrack = onTrack.filter(a => a.site === 'RMT');
const cltTrack = onTrack.filter(a => a.site !== 'RMT');

const trackLines = [];
if (rmtTrack.length > 0) trackLines.push(`*RMT* (${rmtTrack.length}): ${rmtTrack.map(a => a.name).join(', ')}`);
if (cltTrack.length > 0) trackLines.push(`*CLT* (${cltTrack.length}): ${cltTrack.map(a => a.name).join(', ')}`);

if (trackLines.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*:white_check_mark: ON TRACK (${onTrack.length})*\n${trackLines.join('\n')}` } });
  blocks.push({ type: 'divider' });
}

const allAgents = [...critical, ...warning, ...onTrack];
const totalPoolSales = allAgents.reduce((s, a) => s + a.poolWeekSales, 0);
const totalPoolAssigns = allAgents.reduce((s, a) => s + a.poolSelfAssigned, 0);
const totalPoolDials = allAgents.reduce((s, a) => s + a.poolDials, 0);
const agentsInPool = allAgents.filter(a => a.poolDials > 0).length;
const agentsPoolGoalMet = allAgents.filter(a => a.poolOnTrack).length;

blocks.push({ type: 'section', text: { type: 'mrkdwn', text:
  `*:busts_in_silhouette: Pool Summary*\n` +
  `${agentsInPool} agents active in pool  \u00b7  ${totalPoolDials} dials  \u00b7  ${totalPoolAssigns} assigns today\n` +
  `${totalPoolSales} pool sales this week  \u00b7  ${agentsPoolGoalMet}/${agentCount} agents hit 1/wk target`
}});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text:
  `Targets: CR ${cfg.CR_TARGET}%+ (1 deal per ${cfg.DAILY_LEADS} leads)  |  Pipeline \u2264${cfg.MAX_PIPELINE}  |  Pool: ${cfg.POOL_DAILY_ASSIGNS} assigns/day, ${cfg.POOL_WEEKLY_SALES} sale/wk  |  Past Due: 0  |  CPC: ${cfg.LEAD_COST}  |  Org avg prem: ${cfg.AVG_PREMIUM_ORG}`
}]});

const fallback = `Hourly Alert \u2014 ${dd} ${ampm}: ${critical.length} critical, ${warning.length} warning, ${onTrack.length} on track`;

return [{ json: { text: fallback, blocks } }];

return [{ json: {
  text: ':x: *Hourly Action Alert failed*\n' + ($input.first().json.error || $input.first().json.message || 'Unknown error — check n8n execution log.')
} }];
